joi_block.script:
hold_ticks := 0
if ((#PresenceSensor).presenceSensor_presence == true) {
hold_ticks = hold_ticks + 1
    if (hold_ticks >= 300) {
(#Switch).switch_on()
        break
}
}
else {
hold_ticks = 0
}

